private void calculateValues(ETG_ChargeCodes _chargeCodes)
{
    AgreementLineQuantityCommitment  commitment;
    PurchAgreementHeader             purchHeader;
    SalesAgreementHeader             salesHeader;
    AgreementLine                    agreementLine;
    AgreementHeader                  agreementHeader;
    MarkupTable                      markupTable;

    CurrencyExchangeHelper exchangeHelper;
    CurrencyCode fromCurrency = Ledger::accountingCurrency();
    CurrencyCode reportingCurrency = Ledger::reportingCurrency();

    select firstOnly markupTable
    where markupTable.MarkupCode == _chargeCodes.MarkupCode;

    if (markupTable)
    _chargeCodes.TransTxt = markupTable.Txt;

    select firstOnly purchHeader
    where purchHeader.PurchNumberSequence == _chargeCodes.PurchNumberSequence;

    if (purchHeader)
    {
        select firstOnly agreementLine
        where agreementLine.Agreement == purchHeader.RecId;

        select firstOnly agreementHeader
        where agreementHeader.RecId == purchHeader.RecId;
    }

    select firstOnly salesHeader
    where salesHeader.SalesNumberSequence == _chargeCodes.PurchNumberSequence;

    if (salesHeader)
    {
        select firstOnly agreementLine
        where agreementLine.Agreement == salesHeader.RecId;

        select firstOnly agreementHeader
        where agreementHeader.RecId == salesHeader.RecId;
    }

    select firstOnly commitment
    where commitment.RecId == agreementLine.RecId;

    if (commitment)
    _chargeCodes.Qty = commitment.CommitedQuantity;

    if (!_chargeCodes.CurrencyCode && commitment)
    _chargeCodes.CurrencyCode = commitment.Currency;

    if (!_chargeCodes.CurrencyCode && agreementHeader)
    _chargeCodes.CurrencyCode = agreementHeader.Currency;

    exchangeHelper = CurrencyExchangeHelper::newExchangeDate(Ledger::current(), systemDateGet());

    if (_chargeCodes.CurrencyCode)
    {
        _chargeCodes.ExchangeRate =
        exchangeHelper.calculateCurrencyToCurrency(_chargeCodes.CurrencyCode,
                                                    fromCurrency,
                                                    1,
                                                    true);

        _chargeCodes.ReportingExchangeRate =
        exchangeHelper.calculateCurrencyToCurrency(_chargeCodes.CurrencyCode,
                                                    reportingCurrency,
                                                    1,
                                                    true);
    }

    if (_chargeCodes.ETG_MarkupCategory == ETG_MarkupCategory::Pcs)
    {
        _chargeCodes.AmountMST = _chargeCodes.Value * _chargeCodes.Qty;
    }
    else if (_chargeCodes.ETG_MarkupCategory == ETG_MarkupCategory::Fixed)
    {
        _chargeCodes.AmountMST = _chargeCodes.Value;
    }
    else if (_chargeCodes.ETG_MarkupCategory == ETG_MarkupCategory::Percentage && commitment)
    {
        _chargeCodes.AmountMST =
    ((commitment.CommitedQuantity * commitment.PricePerUnit) -
    ((commitment.LineDiscountPercent *
     (commitment.CommitedQuantity * commitment.PricePerUnit)) / 100)) *
     (_chargeCodes.Value / 100);
    }

    _chargeCodes.Amountinaccountingcurrency = _chargeCodes.ExchangeRate * _chargeCodes.AmountMST;
    _chargeCodes.Amountinreportingcurrency  = _chargeCodes.ReportingExchangeRate * _chargeCodes.AmountMST;
}

/// <summary>
/// This method sets fields like exchange rate, amount when Charge code is inserted
/// </summary>
/// <param name = "_entityCtx"></param>
/// <param name = "_dataSourceCtx"></param>
public void mapEntityToDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    super(_entityCtx, _dataSourceCtx);
    ETG_ChargeCodes chargeCodes = _dataSourceCtx.getBuffer();
    this.calculateValues(chargeCodes);
}
